import React, { useState } from 'react';
import { 
  User, 
  FileEdit, 
  Calendar,
  ArrowLeft, 
  ArrowRight, 
  Check,
  Hash,
  Users,
  FileText,
  Plus,
  Trash2
} from 'lucide-react';

const ClientForm = () => {
  const [currentSection, setCurrentSection] = useState(0);
  const [formData, setFormData] = useState({
    clientNumber: '',
    clientName: '',
    hearingDate: '',
    riders: [{
      aNumber: '',
      name: '',
      isMinor: false
    }],
    additionalNotes: ''
  });

  const sections = [
    {
      title: 'Client Information',
      description: 'Enter basic client details',
      icon: User,
      color: 'bg-gradient-to-r from-blue-600 to-indigo-600'
    },
    {
      title: 'Case Details',
      description: 'Add case specific information',
      icon: FileEdit,
      color: 'bg-gradient-to-r from-purple-600 to-pink-600'
    },
    {
      title: 'Schedule',
      description: 'Set hearing dates',
      icon: Calendar,
      color: 'bg-gradient-to-r from-green-600 to-teal-600'
    }
  ];

  const formatANumber = (value) => {
    // Remove all non-digits
    const numbers = value.replace(/\D/g, '');
    
    // Add dashes after every 3 digits
    const matches = numbers.match(/\d{1,3}/g);
    if (matches) {
      return matches.join('-').substr(0, 11); // Limit to 9 digits + 2 dashes
    }
    return '';
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    if (name === 'clientNumber') {
      setFormData(prev => ({
        ...prev,
        [name]: formatANumber(value)
      }));
    } else {
      setFormData(prev => ({
        ...prev,
        [name]: value
      }));
    }
  };

  const handleRiderChange = (index, field, value) => {
    const updatedRiders = [...formData.riders];
    if (field === 'aNumber') {
      updatedRiders[index][field] = formatANumber(value);
    } else {
      updatedRiders[index][field] = value;
    }
    setFormData(prev => ({
      ...prev,
      riders: updatedRiders
    }));
  };

  const addRider = () => {
    setFormData(prev => ({
      ...prev,
      riders: [...prev.riders, { aNumber: '', name: '', isMinor: false }]
    }));
  };

  const removeRider = (index) => {
    setFormData(prev => ({
      ...prev,
      riders: prev.riders.filter((_, i) => i !== index)
    }));
  };

  const handleNextSection = () => {
    if (currentSection < sections.length - 1) {
      setCurrentSection(curr => curr + 1);
    }
  };

  const handlePreviousSection = () => {
    if (currentSection > 0) {
      setCurrentSection(curr => curr - 1);
    }
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Form submitted:', formData);
  };

  const renderClientInfoSection = () => (
    <div className="space-y-6 animate-fadeIn">
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="space-y-2">
          <label className="text-sm font-medium text-white">Client A#</label>
          <div className="relative group">
            <Hash className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 group-hover:text-blue-500 transition-colors" />
            <input
              type="text"
              name="clientNumber"
              value={formData.clientNumber}
              onChange={handleInputChange}
              placeholder="123-456-789"
              className="pl-10 w-full rounded-lg border border-gray-600 bg-gray-700 p-3 text-sm text-white
                       transition-all duration-200 
                       focus:ring-2 focus:ring-blue-500 focus:border-transparent
                       hover:border-blue-500"
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-white">Client Name</label>
          <div className="relative group">
            <Users className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 group-hover:text-blue-500 transition-colors" />
            <input
              type="text"
              name="clientName"
              value={formData.clientName}
              onChange={handleInputChange}
              className="pl-10 w-full rounded-lg border border-gray-600 bg-gray-700 p-3 text-sm text-white
                       transition-all duration-200
                       focus:ring-2 focus:ring-blue-500 focus:border-transparent
                       hover:border-blue-500"
              placeholder="Enter client name"
            />
          </div>
        </div>

        <div className="space-y-2">
          <label className="text-sm font-medium text-white">Hearing Date</label>
          <div className="relative group">
            <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 group-hover:text-blue-500 transition-colors" />
            <input
              type="date"
              name="hearingDate"
              value={formData.hearingDate}
              onChange={handleInputChange}
              className="pl-10 w-full rounded-lg border border-gray-600 bg-gray-700 p-3 text-sm text-white
                       transition-all duration-200
                       focus:ring-2 focus:ring-blue-500 focus:border-transparent
                       hover:border-blue-500"
            />
          </div>
        </div>
      </div>

      {/* Riders Section */}
      <div className="space-y-4">
        <div className="flex justify-between items-center">
          <label className="text-sm font-medium text-white">Riders</label>
          <button
            type="button"
            onClick={addRider}
            className="flex items-center px-3 py-1 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-all"
          >
            <Plus className="h-4 w-4 mr-1" />
            Add Rider
          </button>
        </div>
        
        {formData.riders.map((rider, index) => (
          <div key={index} className="grid grid-cols-1 md:grid-cols-3 gap-4 p-4 border border-gray-600 rounded-lg">
            <div className="space-y-2">
              <label className="text-sm font-medium text-white">Rider A#</label>
              <div className="relative">
                <Hash className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                <input
                  type="text"
                  value={rider.aNumber}
                  onChange={(e) => handleRiderChange(index, 'aNumber', e.target.value)}
                  placeholder="123-456-789"
                  className="pl-10 w-full rounded-lg border border-gray-600 bg-gray-700 p-3 text-sm text-white
                           focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
            </div>
            
            <div className="space-y-2">
              <label className="text-sm font-medium text-white">Rider Name</label>
              <div className="relative">
                <Users className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" />
                <input
                  type="text"
                  value={rider.name}
                  onChange={(e) => handleRiderChange(index, 'name', e.target.value)}
                  placeholder="Enter rider name"
                  className="pl-10 w-full rounded-lg border border-gray-600 bg-gray-700 p-3 text-sm text-white
                           focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
            </div>
            
            <div className="flex items-center justify-between space-x-4">
              <div className="flex items-center">
                <input
                  type="checkbox"
                  checked={rider.isMinor}
                  onChange={(e) => handleRiderChange(index, 'isMinor', e.target.checked)}
                  className="w-4 h-4 text-blue-600 rounded focus:ring-blue-500"
                />
                <label className="ml-2 text-sm font-medium text-white">Minor</label>
              </div>
              
              {formData.riders.length > 1 && (
                <button
                  type="button"
                  onClick={() => removeRider(index)}
                  className="p-2 text-red-400 hover:text-red-300 transition-colors"
                >
                  <Trash2 className="h-5 w-5" />
                </button>
              )}
            </div>
          </div>
        ))}
      </div>

      <div className="space-y-2">
        <label className="text-sm font-medium text-white">Additional Notes</label>
        <div className="relative group">
          <FileText className="absolute left-3 top-3 text-gray-400 group-hover:text-blue-500 transition-colors" />
          <textarea
            name="additionalNotes"
            value={formData.additionalNotes}
            onChange={handleInputChange}
            rows="4"
            className="pl-10 w-full rounded-lg border border-gray-600 bg-gray-700 p-3 text-sm text-white
                     transition-all duration-200
                     focus:ring-2 focus:ring-blue-500 focus:border-transparent
                     hover:border-blue-500"
            placeholder="Enter any additional notes"
          />
        </div>
      </div>
    </div>
  );

  const renderCurrentSection = () => {
    switch (currentSection) {
      case 0:
        return renderClientInfoSection();
      case 1:
      case 2:
        return (
          <div className="p-8 text-center text-gray-400 animate-fadeIn">
            <div className="mb-4">
              <FileEdit className="h-16 w-16 mx-auto text-gray-400" />
            </div>
            <h3 className="text-xl font-semibold mb-2 text-white">Coming Soon</h3>
            <p>This section is under development</p>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 p-6">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-white mb-2">Client Information System</h1>
          <p className="text-gray-400">Manage your client information efficiently</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
          {sections.map((section, index) => {
            const Icon = section.icon;
            return (
              <div
                key={index}
                onClick={() => setCurrentSection(index)}
                className={`relative cursor-pointer rounded-xl p-6 ${
                  index === currentSection 
                    ? section.color 
                    : 'bg-gray-800'
                } transform transition-all duration-300 hover:scale-105 hover:shadow-xl shadow-lg`}
              >
                <div className="flex items-center space-x-4">
                  <div className={`p-3 rounded-lg ${
                    index === currentSection 
                      ? 'bg-white/20' 
                      : 'bg-gray-700'
                  }`}>
                    <Icon className={`h-6 w-6 ${
                      index === currentSection 
                        ? 'text-white' 
                        : 'text-gray-400'
                    }`} />
                  </div>
                  <div>
                    <h3 className="font-semibold text-white">
                      {section.title}
                    </h3>
                    <p className={`text-sm ${
                      index === currentSection 
                        ? 'text-white/80' 
                        : 'text-gray-400'
                    }`}>
                      {section.description}
                    </p>
                  </div>
                </div>
                {index === currentSection && (
                  <div className="absolute -top-2 -right-2">
                    <div className="bg-blue-600 rounded-full p-1.5 shadow-lg">
                      <Check className="h-4 w-4 text-white" />
                    </div>
                  </div>
                )}
              </div>
            );
          })}
        </div>

        <div className="bg-gray-800 rounded-xl shadow-lg p-8 mb-8 border border-gray-700">
          <form onSubmit={handleSubmit}>
            {renderCurrentSection()}
          </form>
        </div>

        <div className="flex justify-between">
          <button
            type="button"
            onClick={handlePreviousSection}
            disabled={currentSection === 0}
            className={`flex items-center px-6 py-3 rounded-lg transition-all ${
              currentSection === 0
                ? 'bg-gray-800 text-gray-400 cursor-not-allowed'
                : 'bg-gray-800 hover:bg-gray-700 text-gray-300 shadow-lg hover:shadow-xl'
            }`}
          >
            <ArrowLeft className="h-5 w-5 mr-2" />
            Previous
          </button>
          
          {currentSection === sections.length - 1 ? (
            <button
              type="submit"
              className="flex items-center px-8 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg hover:from-blue-700 hover:to-indigo-700 transition-all shadow-lg hover:shadow-xl"
            >
              <Check className="h-5 w-5 mr-2" />
              Submit Form
            </button>
          ) : (
            <button
            type="button"
            onClick={handleNextSection}
            className="flex items-center px-6 py-3 bg-gradient-to-r from-blue-600 to-indigo-600 text-white rounded-lg hover:from-blue-700 hover:to-indigo-700 transition-all shadow-lg hover:shadow-xl"
          >
            Next
            <ArrowRight className="h-5 w-5 ml-2" />
          </button>
        )}
      </div>
    </div>
  </div>
);
};

export default ClientForm;
